#include <stdio.h>
#include <stdint.h>

/* Status Register Flags */
typedef struct {
 uint8_t Z:1; // Zero flag
 uint8_t C:1; // Carry flag
 uint8_t N:1; // Negative flag
 uint8_t V:1; // Overflow flag
} StatusFlags;

/* ALU Structure */
typedef struct {
 uint8_t result;
 StatusFlags flags;
} ALU;

/* Initialize ALU */
void alu_init(ALU *alu) {
 alu->result = 0;
 alu->flags.Z = 0;
 alu->flags.C = 0;
 alu->flags.N = 0;
 alu->flags.V = 0;
}

/* Update status flags based on result */
void update_flags(ALU *alu, uint8_t result, uint8_t op1, uint8_t op2, char op) {
 alu->result = result;

 // Zero flag
 alu->flags.Z = (result == 0) ? 1 : 0;

 // Negative flag (MSB indicates negative in signed)
 alu->flags.N = (result & 0x80) ? 1 : 0;

 // Carry and Overflow for arithmetic operations
 if (op == '+' || op == '-') {
 int sum = (op == '+') ? (op1 + op2) : (op1 - op2);

 // Carry: unsigned overflow
 alu->flags.C = (sum > 255 || sum < 0) ? 1 : 0;

 // Overflow: signed overflow (same sign inputs, different sign result)
 if (op == '+') {
 alu->flags.V = ((op1 & 0x80) == (op2 & 0x80)) && 
 ((op1 & 0x80) != (result & 0x80));
 } else {
 alu->flags.V = ((op1 & 0x80) != (op2 & 0x80)) && 
 ((op1 & 0x80) != (result & 0x80));
 }
 }
}

/* ALU Operations */
uint8_t alu_add(ALU *alu, uint8_t a, uint8_t b) {
 uint8_t result = a + b;
 update_flags(alu, result, a, b, '+');
 return result;
}

uint8_t alu_sub(ALU *alu, uint8_t a, uint8_t b) {
 uint8_t result = a - b;
 update_flags(alu, result, a, b, '-');
 return result;
}

uint8_t alu_and(ALU *alu, uint8_t a, uint8_t b) {
 uint8_t result = a & b;
 update_flags(alu, result, a, b, '&');
 return result;
}

uint8_t alu_or(ALU *alu, uint8_t a, uint8_t b) {
 uint8_t result = a | b;
 update_flags(alu, result, a, b, '|');
 return result;
}

uint8_t alu_xor(ALU *alu, uint8_t a, uint8_t b) {
 uint8_t result = a ^ b;
 update_flags(alu, result, a, b, '^');
 return result;
}

uint8_t alu_not(ALU *alu, uint8_t a) {
 uint8_t result = ~a;
 update_flags(alu, result, a, 0, '~');
 return result;
}

/* Display ALU state */
void alu_display(ALU *alu) {
 printf("Result: 0x%02X (%d)\n", alu->result, alu->result);
 printf("Flags: Z=%d C=%d N=%d V=%d\n", 
 alu->flags.Z, alu->flags.C, 
 alu->flags.N, alu->flags.V);
}

/* Register File Simulation */
typedef struct {
 uint8_t R0, R1, R2, R3; // General purpose
 uint8_t PC; // Program Counter
 uint8_t IR; // Instruction Register
 uint8_t MAR; // Memory Address Register
 uint8_t MBR; // Memory Buffer Register
 uint8_t ACC; // Accumulator
 StatusFlags SR; // Status Register
} CPU registers;

void display_registers(CPU registers *reg) {
 printf("\n--- CPU Registers ---\n");
 printf("ACC=%d R0=%d R1=%d R2=%d R3=%d\n", 
 reg->ACC, reg->R0, reg->R1, reg->R2, reg->R3);
 printf("PC=%d IR=0x%02X MAR=%d MBR=%d\n",
 reg->PC, reg->IR, reg->MAR, reg->MBR);
}

int main() {
 ALU alu;
 CPU registers reg = {0};

 printf("=== ALU Demonstration ===\n");

 // ADD operation: 200 + 80 = 280 (overflow, carry set)
 printf("\n1. ADD: 200 + 80\n");
 reg.ACC = alu_add(&alu, 200, 80);
 alu_display(&alu);

 // AND operation
 printf("\n2. AND: 0xF0 & 0x0F\n");
 reg.ACC = alu_and(&alu, 0xF0, 0x0F);
 alu_display(&alu);

 // OR operation
 printf("\n3. OR: 0x0A | 0x05\n");
 reg.ACC = alu_or(&alu, 0x0A, 0x05);
 alu_display(&alu);

 // XOR operation
 printf("\n4. XOR: 0xFF ^ 0x0F\n");
 reg.ACC = alu_xor(&alu, 0xFF, 0x0F);
 alu_display(&alu);

 // NOT operation
 printf("\n5. NOT: ~0x55\n");
 reg.ACC = alu_not(&alu, 0x55);
 alu_display(&alu);

 // SUB operation: 50 - 100 (negative result)
 printf("\n6. SUB: 50 - 100\n");
 reg.ACC = alu_sub(&alu, 50, 100);
 alu_display(&alu);

 // Demonstrate register operations
 printf("\n=== Register Operations ===\n");
 reg.R0 = 100;
 reg.R1 = 50;
 reg.ACC = alu_sub(&alu, reg.R0, reg.R1);
 display_registers(&reg);

 return 0;
}
